Here is a simple C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>

int main() {
    std::string filename = "input.txt"; // Replace with your file name
    std::string searchWord = "wordToFind"; // Replace with the word to search for
    std::ifstream file(filename);
    int count = 0;

    if (file.is_open()) {
        std::string line;
        while (getline(file, line)) {
            size_t pos = 0;
            while ((pos = line.find(searchWord, pos)) != std::string::npos) {
                count++;
                pos += searchWord.length();
            }
        }
        file.close();
    } else {
        std::cerr << "Unable to open file: " << filename << std::endl;
        return 1;
    }

    std::cout << "The word '" << searchWord << "' occurs " << count << " times in the file." << std::endl;

    return 0;
}
```

Replace `input.txt` with the name of your input file and `wordToFind` with the word you want to search for. This program uses the `std::ifstream` class to open the file, `std::getline()` to read lines, and `std::string::find()` to search for the word within each line. The number of occurrences is kept in a variable named `count`.
